47: public class ChannelBuilders {
48:     private static final Logger log = LoggerFactory.getLogger(ChannelBuilders.class);
49: 
50:     private ChannelBuilders() { }
51: 
52:     /**
53:      * @param securityProtocol the securityProtocol
54:      * @param contextType the contextType, it must be non-null if `securityProtocol` is SASL_*; it is ignored otherwise
55:      * @param config client config
56:      * @param listenerName the listenerName if contextType is SERVER or null otherwise
57:      * @param clientSaslMechanism SASL mechanism if mode is CLIENT, ignored otherwise
58:      * @param time the time instance
59:      * @param logContext the log context instance
60:      *
61:      * @return the configured `ChannelBuilder`
62:      * @throws IllegalArgumentException if `mode` invariants described above is not maintained
63:      */
64:     public static ChannelBuilder clientChannelBuilder(
65:             SecurityProtocol securityProtocol,
66:             JaasContext.Type contextType,
67:             AbstractConfig config,
68:             ListenerName listenerName,
69:             String clientSaslMechanism,
70:             Time time,
71:             LogContext logContext) {
72: 
73:         if (securityProtocol == SecurityProtocol.SASL_PLAINTEXT || securityProtocol == SecurityProtocol.SASL_SSL) {
74:             if (contextType == null)
75:                 throw new IllegalArgumentException("`contextType` must be non-null if `securityProtocol` is `" + securityProtocol + "`");
76:             if (clientSaslMechanism == null)
77:                 throw new IllegalArgumentException("`clientSaslMechanism` must be non-null in client mode if `securityProtocol` is `" + securityProtocol + "`");
78:         }
79:         return create(securityProtocol, ConnectionMode.CLIENT, contextType, config, listenerName, false, clientSaslMechanism,
80:             null, null, time, logContext, null);
81:     }
82: 
83:     /**
84:      * @param listenerName the listenerName
85:      * @param isInterBrokerListener whether or not this listener is used for inter-broker requests
86:      * @param securityProtocol the securityProtocol
87:      * @param config server config
88:      * @param credentialCache Credential cache for SASL/SCRAM if SCRAM is enabled
89:      * @param tokenCache Delegation token cache
90:      * @param time the time instance
91:      * @param logContext the log context instance
92:      * @param apiVersionSupplier supplier for ApiVersions responses sent prior to authentication
93:      *
94:      * @return the configured `ChannelBuilder`
95:      */
96:     public static ChannelBuilder serverChannelBuilder(ListenerName listenerName,
97:                                                       boolean isInterBrokerListener,
98:                                                       SecurityProtocol securityProtocol,
99:                                                       AbstractConfig config,
100:                                                       CredentialCache credentialCache,
101:                                                       DelegationTokenCache tokenCache,
102:                                                       Time time,
103:                                                       LogContext logContext,
104:                                                       Function<Short, ApiVersionsResponse> apiVersionSupplier) {
105:         return create(securityProtocol, ConnectionMode.SERVER, JaasContext.Type.SERVER, config, listenerName,
106:                 isInterBrokerListener, null, credentialCache, tokenCache, time, logContext,
107:                 apiVersionSupplier);
108:     }
109: 
110:     private static ChannelBuilder create(SecurityProtocol securityProtocol,
111:                                          ConnectionMode connectionMode,
112:                                          JaasContext.Type contextType,
113:                                          AbstractConfig config,
114:                                          ListenerName listenerName,
115:                                          boolean isInterBrokerListener,
116:                                          String clientSaslMechanism,
117:                                          CredentialCache credentialCache,
118:                                          DelegationTokenCache tokenCache,
119:                                          Time time,
120:                                          LogContext logContext,
121:                                          Function<Short, ApiVersionsResponse> apiVersionSupplier) {
122:         Map<String, Object> configs = channelBuilderConfigs(config, listenerName);
123: 
124:         ChannelBuilder channelBuilder;
125:         switch (securityProtocol) {
126:             case SSL:
127:                 requireNonNullMode(connectionMode, securityProtocol);
128:                 channelBuilder = new SslChannelBuilder(connectionMode, listenerName, isInterBrokerListener, logContext);
129:                 break;
130:             case SASL_SSL:
131:             case SASL_PLAINTEXT:
132:                 requireNonNullMode(connectionMode, securityProtocol);
133:                 Map<String, JaasContext> jaasContexts;
134:                 String sslClientAuthOverride = null;
135:                 if (connectionMode == ConnectionMode.SERVER) {
136:                     @SuppressWarnings("unchecked")
137:                     List<String> enabledMechanisms = (List<String>) configs.get(BrokerSecurityConfigs.SASL_ENABLED_MECHANISMS_CONFIG);
138:                     jaasContexts = new HashMap<>(enabledMechanisms.size());
139:                     for (String mechanism : enabledMechanisms)
140:                         jaasContexts.put(mechanism, JaasContext.loadServerContext(listenerName, mechanism, configs));
141: 
142:                     // SSL client authentication is enabled in brokers for SASL_SSL only if listener-prefixed config is specified.
143:                     if (listenerName != null && securityProtocol == SecurityProtocol.SASL_SSL) {
144:                         String configuredClientAuth = (String) configs.get(BrokerSecurityConfigs.SSL_CLIENT_AUTH_CONFIG);
145:                         String listenerClientAuth = (String) config.originalsWithPrefix(listenerName.configPrefix(), true)
146:                                 .get(BrokerSecurityConfigs.SSL_CLIENT_AUTH_CONFIG);
147: 
148:                         // If `ssl.client.auth` is configured at the listener-level, we don't set an override and SslFactory
149:                         // uses the value from `configs`. If not, we propagate `sslClientAuthOverride=NONE` to SslFactory and
150:                         // it applies the override to the latest configs when it is configured or reconfigured. `Note that
151:                         // ssl.client.auth` cannot be dynamically altered.
152:                         if (listenerClientAuth == null) {
153:                             sslClientAuthOverride = SslClientAuth.NONE.name().toLowerCase(Locale.ROOT);
154:                             if (configuredClientAuth != null && !configuredClientAuth.equalsIgnoreCase(SslClientAuth.NONE.name())) {
155:                                 log.warn("Broker configuration '{}' is applied only to SSL listeners. Listener-prefixed configuration can be used" +
156:                                         " to enable SSL client authentication for SASL_SSL listeners. In future releases, broker-wide option without" +
157:                                         " listener prefix may be applied to SASL_SSL listeners as well. All configuration options intended for specific" +
158:                                         " listeners should be listener-prefixed.", BrokerSecurityConfigs.SSL_CLIENT_AUTH_CONFIG);
159:                             }
160:                         }
161:                     }
162:                 } else {
163:                     // Use server context for inter-broker client connections and client context for other clients
164:                     JaasContext jaasContext = contextType == JaasContext.Type.CLIENT ? JaasContext.loadClientContext(configs) :
165:                             JaasContext.loadServerContext(listenerName, clientSaslMechanism, configs);
166:                     jaasContexts = Collections.singletonMap(clientSaslMechanism, jaasContext);
167:                 }
168:                 channelBuilder = new SaslChannelBuilder(connectionMode,
169:                         jaasContexts,
170:                         securityProtocol,
171:                         listenerName,
172:                         isInterBrokerListener,
173:                         clientSaslMechanism,
174:                         credentialCache,
175:                         tokenCache,
176:                         sslClientAuthOverride,
177:                         time,
178:                         logContext,
179:                         apiVersionSupplier);
180:                 break;
181:             case PLAINTEXT:
182:                 channelBuilder = new PlaintextChannelBuilder(listenerName);
183:                 break;
184:             default:
185:                 throw new IllegalArgumentException("Unexpected securityProtocol " + securityProtocol);
186:         }
187: 
188:         channelBuilder.configure(configs);
189:         return channelBuilder;
190:     }
191: 
192:     /**
193:      * @return a mutable RecordingMap. The elements got from RecordingMap are marked as "used".
194:      */
195:     @SuppressWarnings("unchecked")
196:     static Map<String, Object> channelBuilderConfigs(final AbstractConfig config, final ListenerName listenerName) {
197:         Map<String, Object> parsedConfigs;
198:         if (listenerName == null)
199:             parsedConfigs = (Map<String, Object>) config.values();
200:         else
201:             parsedConfigs = config.valuesWithPrefixOverride(listenerName.configPrefix());
202: 
203:         config.originals().entrySet().stream()
204:             .filter(e -> !parsedConfigs.containsKey(e.getKey())) // exclude already parsed configs
205:             // exclude already parsed listener prefix configs
206:             .filter(e -> !(listenerName != null && e.getKey().startsWith(listenerName.configPrefix()) &&
207:                 parsedConfigs.containsKey(e.getKey().substring(listenerName.configPrefix().length()))))
208:             // exclude keys like `{mechanism}.some.prop` if "listener.name." prefix is present and key `some.prop` exists in parsed configs.
209:             .filter(e -> !(listenerName != null && parsedConfigs.containsKey(e.getKey().substring(e.getKey().indexOf('.') + 1))))
210:             .forEach(e -> parsedConfigs.put(e.getKey(), e.getValue()));
211:         return parsedConfigs;
212:     }
213: 
214:     private static void requireNonNullMode(ConnectionMode connectionMode, SecurityProtocol securityProtocol) {
215:         if (connectionMode == null)
216:             throw new IllegalArgumentException("`mode` must be non-null if `securityProtocol` is `" + securityProtocol + "`");
217:     }
218: 
219:     public static KafkaPrincipalBuilder createPrincipalBuilder(Map<String, ?> configs,
220:                                                                KerberosShortNamer kerberosShortNamer,
221:                                                                SslPrincipalMapper sslPrincipalMapper) {
222:         Class<?> principalBuilderClass = (Class<?>) configs.get(BrokerSecurityConfigs.PRINCIPAL_BUILDER_CLASS_CONFIG);
223:         final KafkaPrincipalBuilder builder;
224: 
225:         if (principalBuilderClass == null || principalBuilderClass == DefaultKafkaPrincipalBuilder.class) {
226:             builder = new DefaultKafkaPrincipalBuilder(kerberosShortNamer, sslPrincipalMapper);
227:         } else if (KafkaPrincipalBuilder.class.isAssignableFrom(principalBuilderClass)) {
228:             builder = (KafkaPrincipalBuilder) Utils.newInstance(principalBuilderClass);
229:         } else {
230:             throw new InvalidConfigurationException("Type " + principalBuilderClass.getName() + " is not " +
231:                     "an instance of " + KafkaPrincipalBuilder.class.getName());
232:         }
233: 
234:         if (builder instanceof Configurable)
235:             ((Configurable) builder).configure(configs);
236: 
237:         return builder;
238:     }
239: 
240: }
