572:     private void handleApiVersionsRequest(RequestContext context, ApiVersionsRequest apiVersionsRequest) throws IOException {
573:         if (saslState != SaslState.HANDSHAKE_OR_VERSIONS_REQUEST)
574:             throw new IllegalStateException("Unexpected ApiVersions request received during SASL authentication state " + saslState);
575: 
576:         if (apiVersionsRequest.hasUnsupportedRequestVersion())
577:             sendKafkaResponse(context, apiVersionsRequest.getErrorResponse(0, Errors.UNSUPPORTED_VERSION.exception()));
578:         else if (!apiVersionsRequest.isValid())
579:             sendKafkaResponse(context, apiVersionsRequest.getErrorResponse(0, Errors.INVALID_REQUEST.exception()));
580:         else {
581:             metadataRegistry.registerClientInformation(new ClientInformation(apiVersionsRequest.data().clientSoftwareName(),
582:                 apiVersionsRequest.data().clientSoftwareVersion()));
583:             sendKafkaResponse(context, apiVersionSupplier.apply(apiVersionsRequest.version()));
584:             setSaslState(SaslState.HANDSHAKE_REQUEST);
585:         }
586:     }
