36: public class PlainServerCallbackHandler implements AuthenticateCallbackHandler {
37: 
38:     private static final String JAAS_USER_PREFIX = "user_";
39:     private List<AppConfigurationEntry> jaasConfigEntries;
40: 
41:     @Override
42:     public void configure(Map<String, ?> configs, String mechanism, List<AppConfigurationEntry> jaasConfigEntries) {
43:         this.jaasConfigEntries = jaasConfigEntries;
44:     }
45: 
46:     @Override
47:     public void handle(Callback[] callbacks) throws IOException, UnsupportedCallbackException {
48:         String username = null;
49:         for (Callback callback: callbacks) {
50:             if (callback instanceof NameCallback)
51:                 username = ((NameCallback) callback).getDefaultName();
52:             else if (callback instanceof PlainAuthenticateCallback) {
53:                 PlainAuthenticateCallback plainCallback = (PlainAuthenticateCallback) callback;
54:                 boolean authenticated = authenticate(username, plainCallback.password());
55:                 plainCallback.authenticated(authenticated);
56:             } else
57:                 throw new UnsupportedCallbackException(callback);
58:         }
59:     }
60: 
61:     protected boolean authenticate(String username, char[] password) throws IOException {
62:         if (username == null)
63:             return false;
64:         else {
65:             String expectedPassword = JaasContext.configEntryOption(jaasConfigEntries,
66:                     JAAS_USER_PREFIX + username,
67:                     PlainLoginModule.class.getName());
68:             return expectedPassword != null && Utils.isEqualConstantTime(password, expectedPassword.toCharArray());
69:         }
70:     }
71: 
72:     @Override
73:     public void close() throws KafkaException {
74:     }
75: 
76: }
