49: /**
50:  * SaslServer implementation for SASL/SCRAM. This server is configured with a callback
51:  * handler for integration with a credential manager. Kafka brokers provide callbacks
52:  * based on a Zookeeper-based password store.
53:  *
54:  * @see <a href="https://tools.ietf.org/html/rfc5802">RFC 5802</a>
55:  */
56: public class ScramSaslServer implements SaslServer {
57: 
58:     private static final Logger log = LoggerFactory.getLogger(ScramSaslServer.class);
59:     private static final Set<String> SUPPORTED_EXTENSIONS = Set.of(ScramLoginModule.TOKEN_AUTH_CONFIG);
60: 
61:     enum State {
62:         RECEIVE_CLIENT_FIRST_MESSAGE,
63:         RECEIVE_CLIENT_FINAL_MESSAGE,
64:         COMPLETE,
65:         FAILED
66:     }
67: 
68:     private final ScramMechanism mechanism;
69:     private final ScramFormatter formatter;
70:     private final CallbackHandler callbackHandler;
71:     private State state;
72:     private ClientFirstMessage clientFirstMessage;
73:     private ServerFirstMessage serverFirstMessage;
74:     private ScramExtensions scramExtensions;
75:     private ScramCredential scramCredential;
76:     private String authorizationId;
77:     private Long tokenExpiryTimestamp;
78: 
79:     public ScramSaslServer(ScramMechanism mechanism, Map<String, ?> props, CallbackHandler callbackHandler) throws NoSuchAlgorithmException {
80:         this.mechanism = mechanism;
81:         this.formatter = new ScramFormatter(mechanism);
82:         this.callbackHandler = callbackHandler;
83:         setState(State.RECEIVE_CLIENT_FIRST_MESSAGE);
84:     }
85: 
86:     /**
87:      * @throws SaslAuthenticationException if the requested authorization id is not the same as username.
88:      * <p>
89:      * <b>Note:</b> This method may throw {@link SaslAuthenticationException} to provide custom error messages
90:      * to clients. But care should be taken to avoid including any information in the exception message that
91:      * should not be leaked to unauthenticated clients. It may be safer to throw {@link SaslException} in
92:      * most cases so that a standard error message is returned to clients.
93:      * </p>
94:      */
95:     @Override
96:     public byte[] evaluateResponse(byte[] response) throws SaslException, SaslAuthenticationException {
97:         try {
98:             switch (state) {
99:                 case RECEIVE_CLIENT_FIRST_MESSAGE:
100:                     this.clientFirstMessage = new ClientFirstMessage(response);
101:                     this.scramExtensions = clientFirstMessage.extensions();
102:                     if (!SUPPORTED_EXTENSIONS.containsAll(scramExtensions.map().keySet())) {
103:                         log.debug("Unsupported extensions will be ignored, supported {}, provided {}",
104:                                 SUPPORTED_EXTENSIONS, scramExtensions.map().keySet());
105:                     }
106:                     String serverNonce = formatter.secureRandomString();
107:                     try {
108:                         String saslName = clientFirstMessage.saslName();
109:                         String username = ScramFormatter.username(saslName);
110:                         NameCallback nameCallback = new NameCallback("username", username);
111:                         ScramCredentialCallback credentialCallback;
112:                         if (scramExtensions.tokenAuthenticated()) {
113:                             DelegationTokenCredentialCallback tokenCallback = new DelegationTokenCredentialCallback();
114:                             credentialCallback = tokenCallback;
115:                             callbackHandler.handle(new Callback[]{nameCallback, tokenCallback});
116:                             if (tokenCallback.tokenOwner() == null)
117:                                 throw new SaslException("Token Authentication failed: Invalid tokenId : " + username);
118:                             this.authorizationId = tokenCallback.tokenOwner();
119:                             this.tokenExpiryTimestamp = tokenCallback.tokenExpiryTimestamp();
120:                         } else {
121:                             credentialCallback = new ScramCredentialCallback();
122:                             callbackHandler.handle(new Callback[]{nameCallback, credentialCallback});
123:                             this.authorizationId = username;
124:                             this.tokenExpiryTimestamp = null;
125:                         }
126:                         this.scramCredential = credentialCallback.scramCredential();
127:                         if (scramCredential == null)
128:                             throw new SaslException("Authentication failed: Invalid user credentials");
129:                         String authorizationIdFromClient = clientFirstMessage.authorizationId();
130:                         if (!authorizationIdFromClient.isEmpty() && !authorizationIdFromClient.equals(username))
131:                             throw new SaslAuthenticationException("Authentication failed: Client requested an authorization id that is different from username");
132: 
133:                         if (scramCredential.iterations() < mechanism.minIterations())
134:                             throw new SaslException("Iterations " + scramCredential.iterations() +  " is less than the minimum " + mechanism.minIterations() + " for " + mechanism);
135:                         this.serverFirstMessage = new ServerFirstMessage(clientFirstMessage.nonce(),
136:                                 serverNonce,
137:                                 scramCredential.salt(),
138:                                 scramCredential.iterations());
139:                         setState(State.RECEIVE_CLIENT_FINAL_MESSAGE);
140:                         return serverFirstMessage.toBytes();
141:                     } catch (SaslException | AuthenticationException e) {
142:                         throw e;
143:                     } catch (Throwable e) {
144:                         throw new SaslException("Authentication failed: Credentials could not be obtained", e);
145:                     }
146: 
147:                 case RECEIVE_CLIENT_FINAL_MESSAGE:
148:                     try {
149:                         ClientFinalMessage clientFinalMessage = new ClientFinalMessage(response);
150:                         if (!clientFinalMessage.nonce().equals(serverFirstMessage.nonce())) {
151:                             throw new SaslException("Invalid client nonce in the final client message.");
152:                         }
153:                         verifyClientProof(clientFinalMessage);
154:                         byte[] serverKey = scramCredential.serverKey();
155:                         byte[] serverSignature = formatter.serverSignature(serverKey, clientFirstMessage, serverFirstMessage, clientFinalMessage);
156:                         ServerFinalMessage serverFinalMessage = new ServerFinalMessage(null, serverSignature);
157:                         clearCredentials();
158:                         setState(State.COMPLETE);
159:                         return serverFinalMessage.toBytes();
160:                     } catch (InvalidKeyException e) {
161:                         throw new SaslException("Authentication failed: Invalid client final message", e);
162:                     }
163: 
164:                 default:
165:                     throw new IllegalSaslStateException("Unexpected challenge in Sasl server state " + state);
166:             }
167:         } catch (SaslException | AuthenticationException e) {
168:             clearCredentials();
169:             setState(State.FAILED);
170:             throw e;
171:         }
172:     }
173: 
174:     @Override
175:     public String getAuthorizationID() {
176:         if (!isComplete())
177:             throw new IllegalStateException("Authentication exchange has not completed");
178:         return authorizationId;
179:     }
180: 
181:     @Override
182:     public String getMechanismName() {
183:         return mechanism.mechanismName();
184:     }
185: 
186:     @Override
187:     public Object getNegotiatedProperty(String propName) {
188:         if (!isComplete())
189:             throw new IllegalStateException("Authentication exchange has not completed");
190:         if (SaslInternalConfigs.CREDENTIAL_LIFETIME_MS_SASL_NEGOTIATED_PROPERTY_KEY.equals(propName))
191:             return tokenExpiryTimestamp; // will be null if token not used
192:         if (SUPPORTED_EXTENSIONS.contains(propName))
193:             return scramExtensions.map().get(propName);
194:         else
195:             return null;
196:     }
197: 
198:     @Override
199:     public boolean isComplete() {
200:         return state == State.COMPLETE;
201:     }
202: 
203:     @Override
204:     public byte[] unwrap(byte[] incoming, int offset, int len) {
205:         if (!isComplete())
206:             throw new IllegalStateException("Authentication exchange has not completed");
207:         throw new IllegalStateException("SCRAM supports neither integrity nor privacy");
208:     }
209: 
210:     @Override
211:     public byte[] wrap(byte[] outgoing, int offset, int len) {
212:         if (!isComplete())
213:             throw new IllegalStateException("Authentication exchange has not completed");
214:         throw new IllegalStateException("SCRAM supports neither integrity nor privacy");
215:     }
216: 
217:     @Override
218:     public void dispose() {
219:     }
220: 
221:     private void setState(State state) {
222:         log.debug("Setting SASL/{} server state to {}", mechanism, state);
223:         this.state = state;
224:     }
225: 
226:     // Visible for testing
227:     void verifyClientProof(ClientFinalMessage clientFinalMessage) throws SaslException {
228:         try {
229:             byte[] expectedStoredKey = scramCredential.storedKey();
230:             byte[] clientSignature = formatter.clientSignature(expectedStoredKey, clientFirstMessage, serverFirstMessage, clientFinalMessage);
231:             byte[] computedStoredKey = formatter.storedKey(clientSignature, clientFinalMessage.proof());
232:             if (!MessageDigest.isEqual(computedStoredKey, expectedStoredKey))
233:                 throw new SaslException("Invalid client credentials");
234:         } catch (InvalidKeyException e) {
235:             throw new SaslException("Sasl client verification failed", e);
236:         }
237:     }
238: 
239:     private void clearCredentials() {
240:         scramCredential = null;
241:         clientFirstMessage = null;
242:         serverFirstMessage = null;
243:     }
244: 
245:     public static class ScramSaslServerFactory implements SaslServerFactory {
246: 
247:         @Override
248:         public SaslServer createSaslServer(String mechanism, String protocol, String serverName, Map<String, ?> props, CallbackHandler cbh)
249:             throws SaslException {
250: 
251:             if (!ScramMechanism.isScram(mechanism)) {
252:                 throw new SaslException(String.format("Requested mechanism '%s' is not supported. Supported mechanisms are '%s'.",
253:                         mechanism, ScramMechanism.mechanismNames()));
254:             }
255:             try {
256:                 return new ScramSaslServer(ScramMechanism.forMechanismName(mechanism), props, cbh);
257:             } catch (NoSuchAlgorithmException e) {
258:                 throw new SaslException("Hash algorithm not supported for mechanism " + mechanism, e);
259:             }
260:         }
261: 
262:         @Override
263:         public String[] getMechanismNames(Map<String, ?> props) {
264:             Collection<String> mechanisms = ScramMechanism.mechanismNames();
265:             return mechanisms.toArray(new String[0]);
266:         }
267:     }
268: }
