23: /**
24:  * <p>Principals in Kafka are defined by a type and a name. The principal type will always be <code>"User"</code>
25:  * for the simple authorizer that is enabled by default, but custom authorizers can leverage different
26:  * principal types (such as to enable group or role-based ACLs). The {@link KafkaPrincipalBuilder} interface
27:  * is used when you need to derive a different principal type from the authentication context, or when
28:  * you need to represent relations between different principals. For example, you could extend
29:  * {@link KafkaPrincipal} in order to link a user principal to one or more role principals.
30:  *
31:  * <p>For custom extensions of {@link KafkaPrincipal}, there two key points to keep in mind:
32:  * <ol>
33:  * <li>To be compatible with the ACL APIs provided by Kafka (including the command line tool), each ACL
34:  *    can only represent a permission granted to a single principal (consisting of a principal type and name).
35:  *    It is possible to use richer ACL semantics, but you must implement your own mechanisms for adding
36:  *    and removing ACLs.
37:  * <li>In general, {@link KafkaPrincipal} extensions are only useful when the corresponding Authorizer
38:  *    is also aware of the extension. If you have a {@link KafkaPrincipalBuilder} which derives user groups
39:  *    from the authentication context (e.g. from an SSL client certificate), then you need a custom
40:  *    authorizer which is capable of using the additional group information.
41:  * </ol>
42:  */
43: public class KafkaPrincipal implements Principal {
44:     public static final String USER_TYPE = "User";
45:     public static final KafkaPrincipal ANONYMOUS = new KafkaPrincipal(KafkaPrincipal.USER_TYPE, "ANONYMOUS");
46: 
47:     private final String principalType;
48:     private final String name;
49:     private volatile boolean tokenAuthenticated;
50: 
51:     public KafkaPrincipal(String principalType, String name) {
52:         this(principalType, name, false);
53:     }
54: 
55:     public KafkaPrincipal(String principalType, String name, boolean tokenAuthenticated) {
56:         this.principalType = requireNonNull(principalType, "Principal type cannot be null");
57:         this.name = requireNonNull(name, "Principal name cannot be null");
58:         this.tokenAuthenticated = tokenAuthenticated;
59:     }
60: 
61:     @Override
62:     public String toString() {
63:         return principalType + ":" + name;
64:     }
65: 
66:     @Override
67:     public boolean equals(Object o) {
68:         if (this == o) return true;
69:         if (o == null) return false;
70:         if (getClass() != o.getClass()) return false;
71: 
72:         KafkaPrincipal that = (KafkaPrincipal) o;
73:         return principalType.equals(that.principalType) && name.equals(that.name);
74:     }
75: 
76:     @Override
77:     public int hashCode() {
78:         int result = principalType != null ? principalType.hashCode() : 0;
79:         result = 31 * result + (name != null ? name.hashCode() : 0);
80:         return result;
81:     }
82: 
83:     @Override
84:     public String getName() {
85:         return name;
86:     }
87: 
88:     public String getPrincipalType() {
89:         return principalType;
90:     }
91: 
92:     public void tokenAuthenticated(boolean tokenAuthenticated) {
93:         this.tokenAuthenticated = tokenAuthenticated;
94:     }
95: 
96:     public boolean tokenAuthenticated() {
97:         return tokenAuthenticated;
98:     }
99: }
