45: /**
46:  * {@code SaslServer} implementation for SASL/OAUTHBEARER in Kafka. An instance
47:  * of {@link OAuthBearerToken} is available upon successful authentication via
48:  * the negotiated property "{@code OAUTHBEARER.token}"; the token could be used
49:  * in a custom authorizer (to authorize based on JWT claims rather than ACLs,
50:  * for example).
51:  */
52: public class OAuthBearerSaslServer implements SaslServer {
53: 
54:     private static final Logger log = LoggerFactory.getLogger(OAuthBearerSaslServer.class);
55:     private static final String NEGOTIATED_PROPERTY_KEY_TOKEN = OAuthBearerLoginModule.OAUTHBEARER_MECHANISM + ".token";
56:     private static final String INTERNAL_ERROR_ON_SERVER = "Authentication could not be performed due to an internal error on the server";
57: 
58:     private final AuthenticateCallbackHandler callbackHandler;
59: 
60:     private boolean complete;
61:     private OAuthBearerToken tokenForNegotiatedProperty = null;
62:     private String errorMessage = null;
63:     private SaslExtensions extensions;
64: 
65:     public OAuthBearerSaslServer(CallbackHandler callbackHandler) {
66:         if (!(Objects.requireNonNull(callbackHandler) instanceof AuthenticateCallbackHandler))
67:             throw new IllegalArgumentException(String.format("Callback handler must be castable to %s: %s",
68:                     AuthenticateCallbackHandler.class.getName(), callbackHandler.getClass().getName()));
69:         this.callbackHandler = (AuthenticateCallbackHandler) callbackHandler;
70:     }
71: 
72:     /**
73:      * @throws SaslAuthenticationException
