39: public class JaasContext {
40: 
41:     private static final Logger LOG = LoggerFactory.getLogger(JaasContext.class);
42: 
43:     private static final String GLOBAL_CONTEXT_NAME_SERVER = "KafkaServer";
44:     private static final String GLOBAL_CONTEXT_NAME_CLIENT = "KafkaClient";
45: 
46:     /**
47:      * Returns an instance of this class.
48:      *
49:      * The context will contain the configuration specified by the JAAS configuration property
50:      * {@link SaslConfigs#SASL_JAAS_CONFIG} with prefix `listener.name.{listenerName}.{mechanism}.`
51:      * with listenerName and mechanism in lower case. The context `KafkaServer` will be returned
52:      * with a single login context entry loaded from the property.
53:      * <p>
54:      * If the property is not defined, the context will contain the default Configuration and
55:      * the context name will be one of:
56:      * <ol>
57:      *   <li>Lowercased listener name followed by a period and the string `KafkaServer`</li>
58:      *   <li>The string `KafkaServer`</li>
59:      *  </ol>
60:      * If both are valid entries in the default JAAS configuration, the first option is chosen.
61:      * </p>
62:      *
63:      * @throws IllegalArgumentException if listenerName or mechanism is not defined.
64:      */
65:     public static JaasContext loadServerContext(ListenerName listenerName, String mechanism, Map<String, ?> configs) {
66:         if (listenerName == null)
67:             throw new IllegalArgumentException("listenerName should not be null for SERVER");
68:         if (mechanism == null)
69:             throw new IllegalArgumentException("mechanism should not be null for SERVER");
70:         String listenerContextName = listenerName.value().toLowerCase(Locale.ROOT) + "." + GLOBAL_CONTEXT_NAME_SERVER;
71:         Password dynamicJaasConfig = (Password) configs.get(mechanism.toLowerCase(Locale.ROOT) + "." + SaslConfigs.SASL_JAAS_CONFIG);
72:         if (dynamicJaasConfig == null && configs.get(SaslConfigs.SASL_JAAS_CONFIG) != null)
73:             LOG.warn("Server config {} should be prefixed with SASL mechanism name, ignoring config", SaslConfigs.SASL_JAAS_CONFIG);
74:         return load(Type.SERVER, listenerContextName, GLOBAL_CONTEXT_NAME_SERVER, dynamicJaasConfig);
75:     }
76: 
77:     /**
78:      * Returns an instance of this class.
79:      *
80:      * If JAAS configuration property {@link SaslConfigs#SASL_JAAS_CONFIG} is specified,
81:      * the configuration object is created by parsing the property value. Otherwise, the default Configuration
82:      * is returned. The context name is always `KafkaClient`.
83:      *
84:      */
85:     public static JaasContext loadClientContext(Map<String, ?> configs) {
86:         Password dynamicJaasConfig = (Password) configs.get(SaslConfigs.SASL_JAAS_CONFIG);
87:         return load(JaasContext.Type.CLIENT, null, GLOBAL_CONTEXT_NAME_CLIENT, dynamicJaasConfig);
88:     }
